// Pseudo-code implementation
void journal_write(void* data, size_t n_blocks) {
size_t first_part = MIN(n_blocks, JOURNAL_SIZE - current_head);
pwrite(fd, data, first_part * B_SIZE, current_head * B_SIZE);

pre.code:
if (n_blocks > first_part) {
    size_t remaining = n_blocks - first_part;
    pwrite(fd, data + (first_part * B_SIZE), remaining * B_SIZE, 0);
}

update_header((current_head + n_blocks) % JOURNAL_SIZE);
